import{execSync}from"node:child_process";import{join}from"./path.js";const hookFileNames=["prepare-commit-msg","commit-msg","pre-{applypatch,commit,merge-commit,push,rebase,receive}","post-{checkout,commit,merge,rewrite}"],getGitHooksPath=(e=".git/hooks",o)=>{try{return execSync("git rev-parse --git-path hooks",{encoding:"utf8",stdio:["pipe","pipe","ignore"],cwd:o}).trim()}catch(o){return e}};export const getGitHookPaths=(e=".git/hooks",o=!0,t)=>{const i=o?getGitHooksPath(e,t):e;return hookFileNames.map(e=>join(i,e))};